SELECT  FROM pdp_domain_package
WHERE workspace_id =
  #{workspaceId,typeHandler=com.pdp.mysql.typehandler.UuidBinaryTypeHandler}
  AND stable_key = #{stableKey}

SELECT  FROM pdp_domain_package
WHERE workspace_id =
  #{workspaceId,typeHandler=com.pdp.mysql.typehandler.UuidBinaryTypeHandler}

  AND (
    stable_key > #{afterStableKey}
    OR (
      stable_key = #{afterStableKey}
      AND id > #{afterId,typeHandler=com.pdp.mysql.typehandler.UuidBinaryTypeHandler}
    )
  )

ORDER BY stable_key, id
LIMIT #{limit}

